import { useEffect } from "react";
import { match } from "ts-pattern";
import { toast } from "sonner";
import { Loader2, PanelLeft } from "lucide-react";
import { getErrorMessage } from "@shared/lib/errors";
import { SidebarInset, useSidebar } from "@/components/ui/sidebar";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useIsMobile } from "@/shared/hooks/use-mobile";
import { useTheme } from "@/app/providers";
import { useUIStore } from "@/shared/stores/uiStore";
import { useSettings, useUpdateSettings } from "../api/settings.queries";
import {
  GeneralSection,
  AISection,
  EnvironmentSection,
  ExperimentalSection,
  AccessSection,
} from "./sections";

const SECTION_LABELS: Record<string, string> = {
  general: "General",
  ai: "AI Providers",
  environment: "Environment",
  experimental: "Experimental",
  access: "Remote Access",
};

export function SettingsPage() {
  const activeSection = useUIStore((s) => s.activeSettingsSection);
  const closeSettings = useUIStore((s) => s.closeSettings);
  const { theme, setTheme } = useTheme();
  const { toggleSidebar } = useSidebar();
  const isMobile = useIsMobile();

  const settingsQuery = useSettings();
  const updateSettingsMutation = useUpdateSettings();

  const settings = settingsQuery.data || {};
  const loading =
    activeSection === "environment"
      ? false // EnvironmentSection manages its own loading state
      : settingsQuery.isLoading;
  const saving = updateSettingsMutation.isPending;

  // ESC closes settings
  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent) {
      if (e.key !== "Escape") return;
      // Don't close if focus is in an input
      const ae = document.activeElement as HTMLElement | null;
      if (
        ae &&
        (ae.tagName === "INPUT" ||
          ae.tagName === "TEXTAREA" ||
          ae.isContentEditable ||
          ae.getAttribute("role") === "textbox")
      )
        return;
      closeSettings();
    }

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [closeSettings]);

  async function saveSetting(key: string, value: unknown): Promise<boolean> {
    try {
      await updateSettingsMutation.mutateAsync({ [key]: value });
      return true;
    } catch (error) {
      console.error("Failed to save setting:", error);
      toast.error(`Failed to save setting: ${getErrorMessage(error)}`);
      return false;
    }
  }

  function renderContent() {
    if (loading) {
      return (
        <div className="flex h-80 items-center justify-center">
          <Loader2 className="text-muted-foreground size-5 animate-spin" />
        </div>
      );
    }

    const sectionProps = { settings, saveSetting };

    return match(activeSection)
      .with("general", () => <GeneralSection {...sectionProps} theme={theme} setTheme={setTheme} />)
      .with("ai", () => <AISection {...sectionProps} />)
      .with("environment", () => <EnvironmentSection />)
      .with("experimental", () => <ExperimentalSection {...sectionProps} />)
      .with("access", () => <AccessSection {...sectionProps} />)
      .exhaustive();
  }

  return (
    <SidebarInset className="min-w-0">
      <div className="bg-bg-surface border-border-subtle flex h-full min-w-0 flex-1 flex-col overflow-hidden rounded-xl border">
        {isMobile && (
          <div className="flex h-11 flex-shrink-0 items-center gap-2 border-b border-border-subtle px-4">
            <button
              type="button"
              aria-label="Open settings menu"
              onClick={toggleSidebar}
              className="text-text-muted hover:text-text-secondary hover:bg-bg-muted -ml-1 flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-lg transition-colors duration-200"
            >
              <PanelLeft className="h-4 w-4" />
            </button>
            <span className="text-sm font-medium text-text-secondary">
              {SECTION_LABELS[activeSection] ?? "Settings"}
            </span>
          </div>
        )}
        <ScrollArea className="flex-1">
          <div className="mx-auto max-w-2xl px-8 py-8">
            {/* Saving indicator */}
            {saving && (
              <div className="text-muted-foreground mb-4 flex items-center gap-2 text-sm">
                <Loader2 className="size-3.5 animate-spin" />
                <span>Saving...</span>
              </div>
            )}

            {renderContent()}
          </div>
        </ScrollArea>
      </div>
    </SidebarInset>
  );
}

