  1→/**
  2→ * AllDiffFileSection — Memoized per-file section for the all-diffs view.
  3→ *
  4→ * Uses IntersectionObserver with 600px rootMargin for lazy-loading diff data
  5→ * when the section approaches the viewport.
  6→ *
  7→ * Scroll-spy (active file tracking) is handled by the parent AllFilesDiffViewer
  8→ * via a centralized scroll event listener — simpler and more reliable than
  9→ * distributed observers across memoized children.
 10→ *
 11→ * CSS `content-visibility: auto` (via `.diff-section-contained`) lets the browser
 12→ * skip layout/paint for offscreen sections.
 13→ */
 14→
 15→import { useState, useRef, useEffect, useCallback, memo } from "react";
 16→import { ChevronDown, ChevronRight } from "lucide-react";
 17→import { DiffViewer } from "./DiffViewer";
 18→import { useFileDiff } from "../api/workspace.queries";
 19→import type { FileChange } from "@/shared/types";
 20→
 21→interface AllDiffFileSectionProps {
 22→  workspaceId: string;
 23→  fileChange: FileChange;
 24→  isActive: boolean;
 25→  sectionRef: (filePath: string, el: HTMLDivElement | null) => void;
 26→  /** Key counter — when it changes, section resets to expanded state */
 27→  expandStateKey: number;
 28→}
 29→
 30→function AllDiffFileSectionInner({
 31→  workspaceId,
 32→  fileChange,
 33→  isActive,
 34→  sectionRef,
 35→  expandStateKey,
 36→}: AllDiffFileSectionProps) {
 37→  const filePath = fileChange.file || fileChange.file_path || "";
 38→  const [collapsedState, setCollapsedState] = useState({
 39→    value: false,
 40→    expandStateKey,
 41→  });
 42→  const [isNearVisible, setIsNearVisible] = useState(false);
 43→  const containerRef = useRef<HTMLDivElement | null>(null);
 44→
 45→  // Collapse state resets to expanded whenever expandStateKey changes,
 46→  // without requiring a state update from an effect.
 47→  const collapsed = collapsedState.expandStateKey === expandStateKey ? collapsedState.value : false;
 48→
 49→  // Register ref for scroll-to-file and parent scroll-spy
 50→  const refCallback = useCallback(
 51→    (el: HTMLDivElement | null) => {
 52→      containerRef.current = el;
 53→      sectionRef(filePath, el);
 54→    },
 55→    [filePath, sectionRef]
 56→  );
 57→
 58→  // IntersectionObserver: lazy loading (600px rootMargin)
 59→  useEffect(() => {
 60→    const el = containerRef.current;
 61→    if (!el) return;
 62→
 63→    const observer = new IntersectionObserver(
 64→      ([entry]) => {
 65→        if (entry.isIntersecting) {
 66→          setIsNearVisible(true);
 67→          observer.disconnect();
 68→        }
 69→      },
 70→      { rootMargin: "600px" }
 71→    );
 72→    observer.observe(el);
 73→    return () => observer.disconnect();
 74→  }, []);
 75→
 76→  // Fetch diff only when near-visible
 77→  const { data, isLoading, error } = useFileDiff(
 78→    isNearVisible ? workspaceId : null,
 79→    isNearVisible ? filePath : null
 80→  );
 81→
 82→  return (
 83→    <div ref={refCallback} data-diff-path={filePath} className="diff-section-contained">
 84→      {/* Sticky file header — two sibling buttons to avoid nesting interactive elements */}
 85→      <div
 86→        className={`flex w-full items-center gap-2 px-3 py-1.5 transition-colors duration-200 ease-[cubic-bezier(.165,.84,.44,1)] ${
 87→          isActive
 88→            ? "bg-muted/60"
 89→            : collapsed
 90→              ? "bg-muted/15 hover:bg-muted/30"
 91→              : "hover:bg-muted/50 bg-[var(--bg-elevated)]"
 92→        }`}
 93→        style={{
 94→          position: "sticky",
 95→          top: 0,
 96→          zIndex: 5,
 97→        }}
 98→      >
 99→        {/* Collapse toggle — covers chevron, path, and stats */}
100→        <button
101→          type="button"
102→          onClick={() =>
103→            setCollapsedState((prev) => ({
104→              value: prev.expandStateKey === expandStateKey ? !prev.value : true,
105→              expandStateKey,
106→            }))
107→          }
108→          className="flex min-w-0 flex-1 items-center gap-2 text-left"
109→        >
110→          {collapsed ? (
111→            <ChevronRight className="text-muted-foreground/60 h-3.5 w-3.5 flex-shrink-0" />
112→          ) : (
113→            <ChevronDown className="text-muted-foreground/60 h-3.5 w-3.5 flex-shrink-0" />
114→          )}
115→
116→          <span
117→            className={`min-w-0 flex-1 truncate text-sm font-medium${
118→              collapsed ? "text-muted-foreground/70" : ""
119→            }`}
120→          >
121→            {filePath}
122→          </span>
123→
124→          {/* +N / -N stats */}
125→          <span className="flex flex-shrink-0 items-center gap-1.5 text-sm tabular-nums">
126→            {fileChange.additions > 0 && (
127→              <span className="text-success/80">+{fileChange.additions}</span>
128→            )}
129→            {fileChange.deletions > 0 && (
130→              <span className="text-destructive/80">-{fileChange.deletions}</span>
